Creating a simple Python web application similar to Twitter involves setting up a basic web framework, a database to store user data and status updates, and a front-end to interact with users. Below is a basic example using Flask for the web framework and SQLite for the database. This example will cover the core functionality: user registration, login, posting status updates, and viewing updates.

### Step 1: Set Up Your Environment

First, ensure you have Python installed. Then, install Flask and Flask-SQLAlchemy:

```bash
pip install Flask Flask-SQLAlchemy
```

### Step 2: Create the Application

Create a file named `app.py` and add the following code:

```python
from flask import Flask, render_template, request, redirect, url_for, session
from flask_sqlalchemy import SQLAlchemy
from datetime import datetime

app = Flask(__name__)
app.config['SECRET_KEY'] = 'your_secret_key'
app.config['SQLALCHEMY_DATABASE_URI'] = 'sqlite:///twitter_clone.db'
db = SQLAlchemy(app)

# Models
class User(db.Model):
    id = db.Column(db.Integer, primary_key=True)
    username = db.Column(db.String(80), unique=True, nullable=False)
    password = db.Column(db.String(120), nullable=False)
    statuses = db.relationship('Status', backref='author', lazy=True)

class Status(db.Model):
    id = db.Column(db.Integer, primary_key=True)
    content = db.Column(db.String(280), nullable=False)
    timestamp = db.Column(db.DateTime, default=datetime.utcnow)
    user_id = db.Column(db.Integer, db.ForeignKey('user.id'), nullable=False)

# Create the database
with app.app_context():
    db.create_all()

# Routes
@app.route('/')
def index():
    statuses = Status.query.order_by(Status.timestamp.desc()).all()
    return render_template('index.html', statuses=statuses)

@app.route('/register', methods=['GET', 'POST'])
def register():
    if request.method == 'POST':
        username = request.form['username']
        password = request.form['password']
        if User.query.filter_by(username=username).first():
            return 'Username already exists!'
        new_user = User(username=username, password=password)
        db.session.add(new_user)
        db.session.commit()
        return redirect(url_for('login'))
    return render_template('register.html')

@app.route('/login', methods=['GET', 'POST'])
def login():
    if request.method == 'POST':
        username = request.form['username']
        password = request.form['password']
        user = User.query.filter_by(username=username, password=password).first()
        if user:
            session['user_id'] = user.id
            return redirect(url_for('index'))
        return 'Invalid credentials!'
    return render_template('login.html')

@app.route('/logout')
def logout():
    session.pop('user_id', None)
    return redirect(url_for('index'))

@app.route('/post', methods=['POST'])
def post():
    if 'user_id' not in session:
        return redirect(url_for('login'))
    content = request.form['content']
    if len(content) > 280:
        return 'Status too long!'
    new_status = Status(content=content, user_id=session['user_id'])
    db.session.add(new_status)
    db.session.commit()
    return redirect(url_for('index'))

if __name__ == '__main__':
    app.run(debug=True)
```

### Step 3: Create Templates

Create a `templates` directory and add the following HTML files:

#### `index.html`

