    super(scope, id, props);

    // Create a KMS Key
    const myKey = new kms.Key(this, 'MyKey', {
      description: 'KMS key for S3 bucket encryption',
      enableKeyRotation: true,
    });

    // Create an S3 Bucket with KMS encryption
    const myBucket = new s3.Bucket(this, 'MyBucket', {
      encryption: s3.BucketEncryption.KMS,
      encryptionKey: myKey,
    });
  }
}
```

### Step 3: Manage Access to the KMS Key

Ensure that the necessary IAM roles or users have permissions to use the KMS key for encryption and decryption. You can attach a policy to a role or user to allow these actions.

```typescript
import * as iam from 'aws-cdk-lib/aws-iam';

